export { parseDiff } from "./parse";
export { computeDiff } from "./compute";
export { resolveDiffInput } from "./resolve";
export { parsedDiffIdentity } from "./identity";
export { computeWordSegments, annotateWordDiff, createWordDiffBudget } from "./word";
export { toSplitRows } from "./split";
export type { ParsedDiff, DiffHunk, DiffChange, ChangeType, DiffInput, DiffInputPatch, DiffInputCompare, DiffInputParsed } from "./parse";
export type { WordSegment, AnnotatedChange, WordDiffBudget } from "./word";
export type { SplitCell, SplitRow } from "./split";

export type ChangeType = "add" | "remove" | "context";

export interface DiffChange {
  type: ChangeType;
  content: string;
  oldLine: number | null;
  newLine: number | null;
}

/** Single-file hunk shape consumed by the diff renderer. */
export interface DiffHunk {
  oldStart: number;
  oldCount: number;
  newStart: number;
  newCount: number;
  heading: string;
  changes: DiffChange[];
}

/** Single-file parsed diff consumed by the diff renderer. */
export interface ParsedDiff {
  oldPath: string | null;
  newPath: string | null;
  hunks: DiffHunk[];
}

export interface DiffInputPatch { patch: string; diff?: never; before?: never; after?: never; }
export interface DiffInputCompare { before: string; after: string; patch?: never; diff?: never; }
export interface DiffInputParsed { diff: ParsedDiff; patch?: never; before?: never; after?: never; }
export type DiffInput = DiffInputPatch | DiffInputCompare | DiffInputParsed;

const HUNK_RE = /^@@\s+-(\d+)(?:,(\d+))?\s+\+(\d+)(?:,(\d+))?\s+@@(.*)$/;

const SKIP_RE = /^(index |new file mode|deleted file mode|old mode|new mode|similarity index|rename from|rename to|Binary files|copy from|copy to)/;

export function parseDiff(patch: string): ParsedDiff[] {
  const lines = patch.split("\n");
  const files: ParsedDiff[] = [];
  let current: ParsedDiff | null = null;
  let hunk: DiffHunk | null = null;
  let oldLine = 0;
  let newLine = 0;

  for (const line of lines) {
    if (line.startsWith("diff --git ")) {
      if (current) files.push(current);
      current = { oldPath: null, newPath: null, hunks: [] };
      hunk = null;
      continue;
    }

    if (SKIP_RE.test(line)) continue;

    if (line.startsWith("--- ")) {
      if (!current) current = { oldPath: null, newPath: null, hunks: [] };
      current.oldPath = line.replace(/^---\s+(?:a\/)?/, "");
      continue;
    }
    if (line.startsWith("+++ ")) {
      if (!current) current = { oldPath: null, newPath: null, hunks: [] };
      current.newPath = line.replace(/^\+\+\+\s+(?:b\/)?/, "");
      continue;
    }

    const m = HUNK_RE.exec(line);
    if (m) {
      if (!current) current = { oldPath: null, newPath: null, hunks: [] };
      hunk = {
        oldStart: Number(m[1]),
        oldCount: Number(m[2] ?? 1),
        newStart: Number(m[3]),
        newCount: Number(m[4] ?? 1),
        heading: (m[5] ?? "").trim(),
        changes: [],
      };
      current.hunks.push(hunk);
      oldLine = hunk.oldStart;
      newLine = hunk.newStart;
      continue;
    }

    if (!hunk) continue;
    if (line.startsWith("\\")) continue;

    if (line.startsWith("-")) {
      hunk.changes.push({ type: "remove", content: line.slice(1), oldLine, newLine: null });
      oldLine++;
    } else if (line.startsWith("+")) {
      hunk.changes.push({ type: "add", content: line.slice(1), oldLine: null, newLine });
      newLine++;
    } else {
      const content = line.startsWith(" ") ? line.slice(1) : line;
      hunk.changes.push({ type: "context", content, oldLine, newLine });
      oldLine++;
      newLine++;
    }
  }

  if (current) files.push(current);

  return files;
}

import type { DiffChange, DiffHunk, ParsedDiff } from "./parse";
import { buildLcsTable } from "./lcs";

const CONTEXT = 3;

export function computeDiff(before: string, after: string): ParsedDiff {
  const oldLines = splitDiffLines(before);
  const newLines = splitDiffLines(after);
  const edits = lcsEdits(oldLines, newLines);
  return { oldPath: null, newPath: null, hunks: groupHunks(edits) };
}

function splitDiffLines(value: string): string[] {
  if (value === "") return [];
  const lines = value.split("\n");
  if (lines[lines.length - 1] === "") lines.pop();
  return lines;
}

function naiveEdits(oldLines: string[], newLines: string[]): DiffChange[] {
  const edits: DiffChange[] = [];
  for (let i = 0; i < oldLines.length; i++) {
    const content = oldLines[i] ?? "";
    edits.push({ type: "remove", content, oldLine: i + 1, newLine: null });
  }
  for (let j = 0; j < newLines.length; j++) {
    const content = newLines[j] ?? "";
    edits.push({ type: "add", content, oldLine: null, newLine: j + 1 });
  }
  return edits;
}

function lcsEdits(oldLines: string[], newLines: string[]): DiffChange[] {
  const dp = buildLcsTable(oldLines, newLines);
  if (!dp) return naiveEdits(oldLines, newLines);

  const m = oldLines.length;
  const n = newLines.length;

  const edits: DiffChange[] = [];
  let i = m;
  let j = n;
  while (i > 0 || j > 0) {
    const oldContent = oldLines[i - 1] ?? "";
    const newContent = newLines[j - 1] ?? "";
    if (i > 0 && j > 0 && oldLines[i - 1] === newLines[j - 1]) {
      edits.push({ type: "context", content: oldContent, oldLine: i, newLine: j });
      i--;
      j--;
      continue;
    }
    const upRow = dp[i - 1] ?? [];
    const curRow = dp[i] ?? [];
    const left = curRow[j - 1] ?? 0;
    const up = upRow[j] ?? 0;
    if (j > 0 && (i === 0 || left >= up)) {
      edits.push({ type: "add", content: newContent, oldLine: null, newLine: j });
      j--;
    } else {
      edits.push({ type: "remove", content: oldContent, oldLine: i, newLine: null });
      i--;
    }
  }
  edits.reverse();
  return edits;
}

function findChangeIndices(edits: DiffChange[]): number[] {
  const indices: number[] = [];
  for (let i = 0; i < edits.length; i++) {
    const edit = edits[i];
    if (edit && edit.type !== "context") indices.push(i);
  }
  return indices;
}

function mergeNearbyRanges(indices: number[], gap: number): [number, number][] {
  const ranges: [number, number][] = [];
  const first = indices[0];
  if (first === undefined) return ranges;
  let start = first;
  let end = first;
  for (let k = 1; k < indices.length; k++) {
    const idx = indices[k];
    if (idx === undefined) continue;
    if (idx - end <= gap) {
      end = idx;
    } else {
      ranges.push([start, end]);
      start = idx;
      end = idx;
    }
  }
  ranges.push([start, end]);
  return ranges;
}

function buildHunk(edits: DiffChange[], range: [number, number], context: number): DiffHunk {
  const from = Math.max(0, range[0] - context);
  const to = Math.min(edits.length - 1, range[1] + context);
  const changes = edits.slice(from, to + 1);

  const firstOld = changes.find((e) => e.oldLine != null);
  const firstNew = changes.find((e) => e.newLine != null);

  let oldCount = 0;
  let newCount = 0;
  for (const e of changes) {
    if (e.type !== "add") oldCount++;
    if (e.type !== "remove") newCount++;
  }

  return {
    oldStart: firstOld?.oldLine ?? 1,
    oldCount,
    newStart: firstNew?.newLine ?? 1,
    newCount,
    heading: "",
    changes,
  };
}

function groupHunks(edits: DiffChange[]): DiffHunk[] {
  const indices = findChangeIndices(edits);
  if (indices.length === 0) return [];
  const ranges = mergeNearbyRanges(indices, CONTEXT * 2 + 1);
  return ranges.map((range) => buildHunk(edits, range, CONTEXT));
}

import type { DiffChange } from "./parse";
import { buildLcsTable } from "./lcs";
import { collectEditPairs } from "./pairs";

export interface WordSegment {
  text: string;
  changed: boolean;
}

export interface AnnotatedChange extends DiffChange {
  wordSegments?: WordSegment[];
}

export interface WordDiffBudget {
  remainingCells: number;
}

export const DEFAULT_WORD_DIFF_CELL_BUDGET = 50_000;

export function createWordDiffBudget(maxCells = DEFAULT_WORD_DIFF_CELL_BUDGET): WordDiffBudget {
  return { remainingCells: maxCells };
}

function changedLineSegments(oldContent: string, newContent: string): { old: WordSegment[]; new: WordSegment[] } {
  return {
    old: [{ text: oldContent, changed: true }],
    new: [{ text: newContent, changed: true }],
  };
}

export function computeWordSegments(
  oldContent: string,
  newContent: string,
  budget?: WordDiffBudget,
): { old: WordSegment[]; new: WordSegment[] } {
  const oldWords = oldContent.split(/(\s+)/);
  const newWords = newContent.split(/(\s+)/);
  const cellCost = oldWords.length * newWords.length;

  if (budget) {
    if (cellCost > budget.remainingCells) {
      return changedLineSegments(oldContent, newContent);
    }
    budget.remainingCells -= cellCost;
  }

  const dp = buildLcsTable(oldWords, newWords);

  if (!dp) {
    return changedLineSegments(oldContent, newContent);
  }

  const m = oldWords.length;
  const n = newWords.length;

  const oldSegs: WordSegment[] = [];
  const newSegs: WordSegment[] = [];
  let i = m;
  let j = n;

  while (i > 0 || j > 0) {
    const oldWord = oldWords[i - 1] ?? "";
    const newWord = newWords[j - 1] ?? "";
    if (i > 0 && j > 0 && oldWords[i - 1] === newWords[j - 1]) {
      oldSegs.push({ text: oldWord, changed: false });
      newSegs.push({ text: newWord, changed: false });
      i--; j--;
      continue;
    }
    const upRow = dp[i - 1] ?? [];
    const curRow = dp[i] ?? [];
    const left = curRow[j - 1] ?? 0;
    const up = upRow[j] ?? 0;
    if (j > 0 && (i === 0 || left >= up)) {
      newSegs.push({ text: newWord, changed: true });
      j--;
    } else {
      oldSegs.push({ text: oldWord, changed: true });
      i--;
    }
  }

  oldSegs.reverse();
  newSegs.reverse();

  return { old: mergeSegments(oldSegs), new: mergeSegments(newSegs) };
}

function mergeSegments(segments: WordSegment[]): WordSegment[] {
  const result: WordSegment[] = [];
  for (const seg of segments) {
    const last = result[result.length - 1];
    if (last && last.changed === seg.changed) {
      last.text += seg.text;
    } else {
      result.push({ text: seg.text, changed: seg.changed });
    }
  }
  return result;
}

export function annotateWordDiff(
  changes: DiffChange[],
  budget = createWordDiffBudget(),
): AnnotatedChange[] {
  const result: AnnotatedChange[] = [];

  for (const item of collectEditPairs(changes)) {
    if ("type" in item) {
      result.push(item);
      continue;
    }

    const { removes, adds } = item;
    const pairs = Math.min(removes.length, adds.length);

    const segmentPairs: { old: WordSegment[]; new: WordSegment[] }[] = [];
    for (let j = 0; j < pairs; j++) {
      const remove = removes[j];
      const add = adds[j];
      if (!remove || !add) continue;
      segmentPairs.push(computeWordSegments(remove.content, add.content, budget));
    }

    for (let j = 0; j < pairs; j++) {
      const remove = removes[j];
      const seg = segmentPairs[j];
      if (!remove || !seg) continue;
      result.push({ ...remove, wordSegments: seg.old });
    }
    for (let j = pairs; j < removes.length; j++) {
      const remove = removes[j];
      if (remove) result.push(remove);
    }

    for (let j = 0; j < pairs; j++) {
      const add = adds[j];
      const seg = segmentPairs[j];
      if (!add || !seg) continue;
      result.push({ ...add, wordSegments: seg.new });
    }
    for (let j = pairs; j < adds.length; j++) {
      const add = adds[j];
      if (add) result.push(add);
    }
  }

  return result;
}

import type { DiffHunk, ChangeType } from "./parse";
import { computeWordSegments, createWordDiffBudget, type WordSegment } from "./word";
import { collectEditPairs } from "./pairs";

export interface SplitCell {
  type: ChangeType | "empty";
  content: string;
  lineNumber: number | null;
  wordSegments?: WordSegment[];
}

export type SplitRow =
  | { kind: "change"; left: SplitCell; right: SplitCell }
  | { kind: "separator"; oldStart: number; oldCount: number; newStart: number; newCount: number; heading: string };

export function toSplitRows(hunks: DiffHunk[], wordDiff: boolean): SplitRow[] {
  const rows: SplitRow[] = [];
  const wordDiffBudget = createWordDiffBudget();

  for (const hunk of hunks) {
    rows.push({
      kind: "separator",
      oldStart: hunk.oldStart,
      oldCount: hunk.oldCount,
      newStart: hunk.newStart,
      newCount: hunk.newCount,
      heading: hunk.heading,
    });

    for (const item of collectEditPairs(hunk.changes)) {
      if ("type" in item) {
        rows.push({
          kind: "change",
          left: { type: "context", content: item.content, lineNumber: item.oldLine },
          right: { type: "context", content: item.content, lineNumber: item.newLine },
        });
        continue;
      }

      const { removes, adds } = item;
      const pairs = Math.max(removes.length, adds.length);

      for (let j = 0; j < pairs; j++) {
        const remove = removes[j];
        const add = adds[j];
        let leftSegs: WordSegment[] | undefined;
        let rightSegs: WordSegment[] | undefined;

        if (wordDiff && remove && add) {
          const { old: oSegs, new: nSegs } = computeWordSegments(remove.content, add.content, wordDiffBudget);
          leftSegs = oSegs;
          rightSegs = nSegs;
        }

        rows.push({
          kind: "change",
          left: remove
            ? { type: "remove", content: remove.content, lineNumber: remove.oldLine, wordSegments: leftSegs }
            : { type: "empty", content: "", lineNumber: null },
          right: add
            ? { type: "add", content: add.content, lineNumber: add.newLine, wordSegments: rightSegs }
            : { type: "empty", content: "", lineNumber: null },
        });
      }
    }
  }

  return rows;
}

const MAX_LCS_CELLS = 250_000;

export function buildLcsTable(a: string[], b: string[]): number[][] | null {
  if (a.length * b.length > MAX_LCS_CELLS) {
    return null;
  }

  const m = a.length;
  const n = b.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => new Array<number>(n + 1).fill(0));
  for (let i = 1; i <= m; i++) {
    const row = dp[i];
    const prevRow = dp[i - 1];
    if (!row || !prevRow) continue;
    for (let j = 1; j <= n; j++) {
      const prevCell = row[j - 1] ?? 0;
      const upLeft = prevRow[j - 1] ?? 0;
      const up = prevRow[j] ?? 0;
      row[j] = a[i - 1] === b[j - 1] ? upLeft + 1 : Math.max(up, prevCell);
    }
  }
  return dp;
}

import type { DiffChange } from "./parse";

export interface EditPairGroup {
  removes: DiffChange[];
  adds: DiffChange[];
}

export function* collectEditPairs(
  changes: DiffChange[],
): Generator<DiffChange | EditPairGroup> {
  let i = 0;
  while (i < changes.length) {
    const head = changes[i];
    if (!head) {
      i++;
      continue;
    }
    if (head.type === "context") {
      yield head;
      i++;
      continue;
    }
    const removes: DiffChange[] = [];
    while (i < changes.length) {
      const next = changes[i];
      if (!next || next.type !== "remove") break;
      removes.push(next);
      i++;
    }
    const adds: DiffChange[] = [];
    while (i < changes.length) {
      const next = changes[i];
      if (!next || next.type !== "add") break;
      adds.push(next);
      i++;
    }
    yield { removes, adds };
  }
}

import type { ParsedDiff, DiffInput } from "./parse";
import { parseDiff } from "./parse";
import { computeDiff } from "./compute";

const EMPTY: ParsedDiff = { oldPath: null, newPath: null, hunks: [] };

export function resolveDiffInput(input: DiffInput): ParsedDiff {
  if ("diff" in input && input.diff != null) return input.diff;
  if ("patch" in input && input.patch != null) return parseDiff(input.patch)[0] ?? EMPTY;
  if ("before" in input && input.before != null && "after" in input && input.after != null) {
    return computeDiff(input.before, input.after);
  }
  return EMPTY;
}

import type { ParsedDiff } from "./parse";

export function parsedDiffIdentity(parsed: ParsedDiff): string {
  const hunks = parsed.hunks
    .map(
      (h) =>
        `${h.oldStart},${h.oldCount},${h.newStart},${h.newCount},${h.changes.length},${h.heading}`,
    )
    .join(";");
  return `${parsed.oldPath ?? ""}\x00${parsed.newPath ?? ""}\x00${parsed.hunks.length}\x00${hunks}`;
}
